  ('disabled-6f0ba476-moex-00631', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '我國於107年採行股利所得課稅新制並廢除兩稅合一設算扣抵制度，有關新 制之敘述，下列何者錯誤？', '["新制可降低適用高邊際稅率之個人居住者與非居住者股東間，股利所得稅 負之差距", "在新制下個人居住者股東之股利所得，得選擇使用28%之稅率分開計稅", "在新制下非居住者股東之股利扣繳稅降低，故可吸引境外資金流入", "新制下營利事業無須記載股東可扣抵稅額帳戶"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:32+00:00", "source_pdf_sha1": "1c20aeb7394a", "answer_pdf_sha1": "470263c0141a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00632', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '有關個人所得稅稅額計算之敘述，下列何者錯誤？', '["在計算所得淨額時，應將可扣抵稅額減除", "在計算應補退稅額時，應將已扣繳稅款減除", "在計算所得淨額時，應減除合於規定之免稅額及扣除額", "在計算應補退稅額時，得減除投資抵減稅額"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:32+00:00", "source_pdf_sha1": "1c20aeb7394a", "answer_pdf_sha1": "470263c0141a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00633', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '下列何項扣除額，依現行稅法規定，並無扣除金額上限之規定？', '["購屋借款利息扣除額", "對國防、勞軍的捐贈扣除額", "租金支出扣除額", "非全民健康保險之保險費扣除額"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:32+00:00", "source_pdf_sha1": "1c20aeb7394a", "answer_pdf_sha1": "470263c0141a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00634', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '有關課徵公司所得稅的租稅歸宿與超額負擔，下列敘述何者錯誤？', '["將公司所得稅視為對公司資本課稅，此即為部分要素稅", "將公司所得稅視為對公司資本課稅，可能會產生超額負擔", "將公司所得稅視為對公司利潤課稅，會產生超額負擔", "將公司所得稅視為對公司利潤課稅，公司無法轉嫁租稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:32+00:00", "source_pdf_sha1": "1c20aeb7394a", "answer_pdf_sha1": "470263c0141a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00635', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '假設政府於去年1月1日宣布，從當年起，於每年7月1日課徵地價稅。甲 為原土地所有人，其於去年4月1日將土地出售給乙，乙又於今年4月1日 將土地出售給丙。若地價稅完全資本化，下列何者為地價稅之經濟歸宿？', '["甲", "乙", "丙", "乙與丙"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:32+00:00", "source_pdf_sha1": "1c20aeb7394a", "answer_pdf_sha1": "470263c0141a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
