  ('disabled-6f0ba476-moex-00639', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', 'A 公司某期之銷項稅額共 20,000 元；可扣抵進項稅額共 60,000 元，其中 有 30,000 元為購買固定資產之進項稅額，該期無零稅率銷售額，則本期應 留抵多少營業稅？', '["0元", "10,000元", "30,000元", "40,000元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:32+00:00", "source_pdf_sha1": "1c20aeb7394a", "answer_pdf_sha1": "470263c0141a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
